def solve(*args):
    if not args:
        return None

    # Assuming args contains project members and invites
    project_members = args[0]
    invites = args[1] if len(args) > 1 else []

    # Process project members
    processed_members = []
    for member in project_members:
        if isinstance(member, str) and member:
            processed_members.append(member)

    # Process invites
    processed_invites = []
    for invite in invites:
        if isinstance(invite, str) and invite:
            processed_invites.append(invite)

    # Return combined results
    return {
        'members': processed_members,
        'invites': processed_invites
    }
